with:
  if "location" in pred_objs:
              # If the location object has its own description, embed it
              loc_obj = clean_obj(pred_objs["location"][0])
              if loc_obj in subj_to_pred_objs:
                  # Build a brief description of the location entity
                  loc_attrs = []
                  loc_pred_objs = subj_to_pred_objs[loc_obj]
                  for key in ["leader", "currency", "demonym", "capital", "language"]:
                      if key in loc_pred_objs:
                          val = ", ".join(clean_obj(v) for v in loc_pred_objs[key])
                          if key == "leader":
                              loc_attrs.append(f"leader {val}")
                          elif key == "currency":
                              loc_attrs.append(f"currency {val}")
                          elif key == "demonym":
                              loc_attrs.append(f"demonym {val}")
                          elif key == "capital":
                              loc_attrs.append(f"capital {val}")
                          elif key == "language":
                              loc_attrs.append(f"language {val}")
                  if loc_attrs:
                      desc = f"{loc_obj} ({', '.join(loc_attrs)})"
                  else:
                      desc = loc_obj
                  parts.append(f"{verb} {desc}")
              else:
                  parts.append(f"{verb} {loc_obj}")
